import { Question } from "@/lib/types";

export const questions: Question[] = [
    { id: "y1f2-001", topicRef: "y1f2", topicTitle: "Connected Particles 01", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["Newton's third law", "action-reaction"], questionText: "A book of mass \\(2\\) kg rests on a horizontal table. State the magnitude and direction of (a) the weight of the book and (b) the normal reaction force exerted by the table on the book. Identify the action-reaction pair according to Newton's third law.", workedSolution: { steps: [{ stepNumber: 1, description: "Calculate the weight of the book.", workingLatex: "W = mg = 2 \\times 9.8 = 19.6 \\text{ N, acting vertically downward}", explanation: "Weight acts downward toward the centre of the Earth." }, { stepNumber: 2, description: "State the normal reaction force.", workingLatex: "R = 19.6 \\text{ N, acting vertically upward}", explanation: "Since the book is in equilibrium on the table, the normal reaction equals the weight in magnitude." }, { stepNumber: 3, description: "Identify the Newton's third law pair.", workingLatex: "\\text{The book pushes down on the table with force } 19.6 \\text{ N; the table pushes up on the book with force } 19.6 \\text{ N.}", explanation: "The action-reaction pair acts on different objects: the book pushes the table (action), and the table pushes the book (reaction). Note: weight and normal reaction are NOT a Newton's third law pair because they both act on the book." }], finalAnswer: "(a) Weight \\(= 19.6\\) N downward. (b) Normal reaction \\(= 19.6\\) N upward. The Newton's third law pair is the book pushing the table down and the table pushing the book up." } },
    { id: "y1f2-002", topicRef: "y1f2", topicTitle: "Connected Particles 02", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["tension", "equilibrium", "vertical string"], questionText: "A particle of mass \\(5\\) kg hangs in equilibrium from a light inextensible string attached to a ceiling. Find the tension in the string.", workedSolution: { steps: [{ stepNumber: 1, description: "Draw a force diagram for the particle. The forces are weight downward and tension upward.", workingLatex: "T - mg = 0", explanation: "The particle is in equilibrium so the net force is zero." }, { stepNumber: 2, description: "Solve for the tension.", workingLatex: "T = mg = 5 \\times 9.8 = 49 \\text{ N}", explanation: "The tension equals the weight of the particle." }], finalAnswer: "\\(T = 49\\) N." } },
    { id: "y1f2-003", topicRef: "y1f2", topicTitle: "Connected Particles 03", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["connected particles", "smooth surface", "acceleration", "tension"], questionText: "Two particles \\(A\\) and \\(B\\), of masses \\(3\\) kg and \\(2\\) kg respectively, are connected by a light inextensible string on a smooth horizontal surface. A horizontal force of \\(25\\) N is applied to \\(A\\) in the direction \\(A\\) to \\(B\\). Find (a) the acceleration of the system and (b) the tension in the string.", workedSolution: { steps: [{ stepNumber: 1, description: "Consider the whole system. The total mass is 3 + 2 = 5 kg and the only horizontal force is 25 N.", workingLatex: "F = ma \\implies 25 = 5a \\implies a = 5 \\text{ m/s}^2", explanation: "Treating the system as a whole gives the acceleration." }, { stepNumber: 2, description: "Consider particle B alone. The only horizontal force on B is the tension T pulling it forward.", workingLatex: "T = m_B \\times a = 2 \\times 5 = 10 \\text{ N}", explanation: "Applying F = ma to particle B gives the tension in the connecting string." }], finalAnswer: "(a) \\(a = 5\\) m/s\\(^2\\). (b) \\(T = 10\\) N." } },
    { id: "y1f2-004", topicRef: "y1f2", topicTitle: "Connected Particles 04", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["Atwood machine", "pulley", "acceleration"], questionText: "Two particles of masses \\(4\\) kg and \\(6\\) kg are connected by a light inextensible string that passes over a smooth fixed pulley. The system is released from rest. Find the acceleration of the system.", workedSolution: { steps: [{ stepNumber: 1, description: "Let the acceleration be a. The heavier mass (6 kg) accelerates downward and the lighter mass (4 kg) accelerates upward.", workingLatex: "\\text{For the 6 kg mass: } 6g - T = 6a", explanation: "Net downward force on the heavier particle." }, { stepNumber: 2, description: "Write the equation of motion for the 4 kg mass.", workingLatex: "\\text{For the 4 kg mass: } T - 4g = 4a", explanation: "Net upward force on the lighter particle." }, { stepNumber: 3, description: "Add the two equations to eliminate T.", workingLatex: "6g - 4g = 10a \\implies 2g = 10a \\implies a = \\frac{2 \\times 9.8}{10} = 1.96 \\text{ m/s}^2", explanation: "The string is inextensible so both particles have the same magnitude of acceleration." }], finalAnswer: "\\(a = 1.96\\) m/s\\(^2\\)." } },
    { id: "y1f2-005", topicRef: "y1f2", topicTitle: "Connected Particles 05", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["Atwood machine", "pulley", "tension"], questionText: "Two particles of masses \\(3\\) kg and \\(7\\) kg are connected by a light inextensible string that passes over a smooth fixed pulley. The system is released from rest. Find the tension in the string.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the acceleration first. The 7 kg mass moves down.", workingLatex: "7g - 3g = (7 + 3)a \\implies 4g = 10a \\implies a = \\frac{4 \\times 9.8}{10} = 3.92 \\text{ m/s}^2", explanation: "Adding the two F = ma equations for each particle." }, { stepNumber: 2, description: "Use the equation of motion for the 3 kg mass to find T.", workingLatex: "T - 3g = 3a \\implies T = 3g + 3a = 3(9.8) + 3(3.92) = 29.4 + 11.76 = 41.16 \\text{ N}", explanation: "The tension pulls the lighter mass upward." }], finalAnswer: "\\(T = 41.16\\) N." } },
    { id: "y1f2-006", topicRef: "y1f2", topicTitle: "Connected Particles 06", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["towing", "constant speed", "tension"], questionText: "A car tows a trailer at a constant speed along a straight horizontal road. The resistance to motion of the trailer is \\(400\\) N. Find the tension in the towbar.", workedSolution: { steps: [{ stepNumber: 1, description: "Since the trailer moves at constant speed, its acceleration is zero.", workingLatex: "a = 0", explanation: "Constant speed means no acceleration." }, { stepNumber: 2, description: "Apply F = ma to the trailer. The forces on the trailer are the tension T forward and resistance 400 N backward.", workingLatex: "T - 400 = 0 \\implies T = 400 \\text{ N}", explanation: "At constant speed the tension exactly balances the resistance." }], finalAnswer: "\\(T = 400\\) N." } },
    { id: "y1f2-007", topicRef: "y1f2", topicTitle: "Connected Particles 07", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["normal reaction", "equilibrium", "table"], questionText: "A box of mass \\(8\\) kg rests on a smooth horizontal table. A vertical string attached to the top of the box exerts an upward pull of \\(20\\) N. Find the normal reaction of the table on the box.", workedSolution: { steps: [{ stepNumber: 1, description: "Draw a force diagram. The forces on the box are: weight 8g downward, normal reaction R upward, and tension 20 N upward.", workingLatex: "R + 20 - 8g = 0", explanation: "The box is in equilibrium vertically." }, { stepNumber: 2, description: "Solve for R.", workingLatex: "R = 8(9.8) - 20 = 78.4 - 20 = 58.4 \\text{ N}", explanation: "The upward pull reduces the normal reaction." }], finalAnswer: "\\(R = 58.4\\) N." } },
    { id: "y1f2-008", topicRef: "y1f2", topicTitle: "Connected Particles 08", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["vertical string", "two masses", "tension"], questionText: "A particle \\(A\\) of mass \\(4\\) kg is suspended from a ceiling by a light inextensible string. A second particle \\(B\\) of mass \\(3\\) kg is suspended from \\(A\\) by another light inextensible string. The system hangs in equilibrium. Find the tension in each string.", workedSolution: { steps: [{ stepNumber: 1, description: "Consider particle B. The only forces are its weight downward and the tension in the lower string upward.", workingLatex: "T_2 = m_B g = 3 \\times 9.8 = 29.4 \\text{ N}", explanation: "The lower string supports the weight of B." }, { stepNumber: 2, description: "Consider particle A. The forces are: its weight 4g downward, the tension T_2 pulling downward (from B), and the tension T_1 in the upper string pulling upward.", workingLatex: "T_1 = m_A g + T_2 = 4(9.8) + 29.4 = 39.2 + 29.4 = 68.6 \\text{ N}", explanation: "The upper string supports the combined weight of A and B." }], finalAnswer: "Tension in the upper string \\(T_1 = 68.6\\) N. Tension in the lower string \\(T_2 = 29.4\\) N." } },
    { id: "y1f2-009", topicRef: "y1f2", topicTitle: "Connected Particles 09", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["Atwood machine", "acceleration", "tension", "simultaneous equations"], questionText: "Two particles \\(P\\) and \\(Q\\), of masses \\(3\\) kg and \\(5\\) kg respectively, are connected by a light inextensible string that passes over a smooth fixed pulley. The system is released from rest. Find (a) the acceleration and (b) the tension in the string.", workedSolution: { steps: [{ stepNumber: 1, description: "Let the acceleration be a. Q (5 kg) moves down and P (3 kg) moves up.", workingLatex: "\\text{For Q: } 5g - T = 5a \\quad \\cdots (1)", explanation: "Net downward force on the heavier particle." }, { stepNumber: 2, description: "Write the equation for P.", workingLatex: "\\text{For P: } T - 3g = 3a \\quad \\cdots (2)", explanation: "Net upward force on the lighter particle." }, { stepNumber: 3, description: "Add (1) and (2) to eliminate T.", workingLatex: "5g - 3g = 8a \\implies 2g = 8a \\implies a = \\frac{2(9.8)}{8} = 2.45 \\text{ m/s}^2", explanation: "" }, { stepNumber: 4, description: "Substitute back into (2) to find T.", workingLatex: "T = 3g + 3a = 3(9.8) + 3(2.45) = 29.4 + 7.35 = 36.75 \\text{ N}", explanation: "" }], finalAnswer: "(a) \\(a = 2.45\\) m/s\\(^2\\). (b) \\(T = 36.75\\) N." } },
    { id: "y1f2-010", topicRef: "y1f2", topicTitle: "Connected Particles 10", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["table and pulley", "smooth surface", "acceleration", "tension"], questionText: "A particle \\(A\\) of mass \\(4\\) kg rests on a smooth horizontal table. It is connected by a light inextensible string that passes over a smooth pulley at the edge of the table to a particle \\(B\\) of mass \\(6\\) kg hanging freely. The system is released from rest. Find (a) the acceleration and (b) the tension in the string.", workedSolution: { steps: [{ stepNumber: 1, description: "Let the acceleration be a. B moves down, A moves horizontally across the table.", workingLatex: "\\text{For B (hanging): } 6g - T = 6a \\quad \\cdots (1)", explanation: "The weight of B drives the system." }, { stepNumber: 2, description: "Write the equation for A on the smooth table.", workingLatex: "\\text{For A (on table): } T = 4a \\quad \\cdots (2)", explanation: "The only horizontal force on A is the tension." }, { stepNumber: 3, description: "Substitute (2) into (1).", workingLatex: "6g - 4a = 6a \\implies 6(9.8) = 10a \\implies a = \\frac{58.8}{10} = 5.88 \\text{ m/s}^2", explanation: "" }, { stepNumber: 4, description: "Find the tension.", workingLatex: "T = 4(5.88) = 23.52 \\text{ N}", explanation: "" }], finalAnswer: "(a) \\(a = 5.88\\) m/s\\(^2\\). (b) \\(T = 23.52\\) N." } },
    { id: "y1f2-011", topicRef: "y1f2", topicTitle: "Connected Particles 11", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["towing", "driving force", "resistance", "acceleration", "tension"], questionText: "A car of mass \\(1200\\) kg tows a trailer of mass \\(400\\) kg along a straight horizontal road. The driving force of the car's engine is \\(3200\\) N. The resistances to motion are \\(600\\) N on the car and \\(200\\) N on the trailer. Find (a) the acceleration and (b) the tension in the towbar.", workedSolution: { steps: [{ stepNumber: 1, description: "Consider the whole system. Total mass = 1200 + 400 = 1600 kg. Net force = driving force minus total resistance.", workingLatex: "F_{\\text{net}} = 3200 - 600 - 200 = 2400 \\text{ N}", explanation: "" }, { stepNumber: 2, description: "Find the acceleration.", workingLatex: "a = \\frac{F_{\\text{net}}}{m_{\\text{total}}} = \\frac{2400}{1600} = 1.5 \\text{ m/s}^2", explanation: "" }, { stepNumber: 3, description: "Consider the trailer alone. The forces on the trailer are tension T forward and resistance 200 N backward.", workingLatex: "T - 200 = 400 \\times 1.5 \\implies T = 600 + 200 = 800 \\text{ N}", explanation: "The tension must accelerate the trailer and overcome its resistance." }], finalAnswer: "(a) \\(a = 1.5\\) m/s\\(^2\\). (b) \\(T = 800\\) N." } },
    { id: "y1f2-012", topicRef: "y1f2", topicTitle: "Connected Particles 12", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Standard", tags: ["towing", "braking", "deceleration", "thrust"], questionText: "A car of mass \\(1000\\) kg tows a trailer of mass \\(500\\) kg along a straight horizontal road at \\(20\\) m/s. The driver applies the brakes, producing a braking force of \\(3000\\) N on the car. The resistance to motion is \\(400\\) N on the car and \\(200\\) N on the trailer. Find (a) the deceleration of the system and (b) the force in the towbar, stating whether it is a tension or a thrust.", workedSolution: { steps: [{ stepNumber: 1, description: "Consider the whole system. Total mass = 1500 kg. The braking force and resistances all oppose the forward motion.", workingLatex: "F_{\\text{net}} = -(3000 + 400 + 200) = -3600 \\text{ N}", explanation: "All forces act backward. The engine driving force is zero during braking." }, { stepNumber: 2, description: "Find the deceleration.", workingLatex: "a = \\frac{-3600}{1500} = -2.4 \\text{ m/s}^2", explanation: "The magnitude of the deceleration is 2.4 m/s^2." }, { stepNumber: 3, description: "Consider the trailer alone. Let F be the force in the towbar (positive = tension, i.e., pulling the trailer forward).", workingLatex: "F - 200 = 500 \\times (-2.4) = -1200", explanation: "F = ma applied to the trailer." }, { stepNumber: 4, description: "Solve for F.", workingLatex: "F = -1200 + 200 = -1000 \\text{ N}", explanation: "The negative sign means the towbar pushes the trailer backward, so it is in thrust (compression), not tension." }], finalAnswer: "(a) Deceleration \\(= 2.4\\) m/s\\(^2\\). (b) The force in the towbar is \\(1000\\) N and it is a thrust (compression)." } },
    { id: "y1f2-013", topicRef: "y1f2", topicTitle: "Connected Particles 13", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["inclined plane", "pulley", "smooth", "acceleration", "tension"], questionText: "A particle \\(A\\) of mass \\(2\\) kg is placed on a smooth plane inclined at \\(30°\\) to the horizontal. It is connected by a light inextensible string passing over a smooth pulley at the top of the plane to a particle \\(B\\) of mass \\(3\\) kg hanging freely on the other side. The system is released from rest. Find (a) the acceleration and (b) the tension in the string.", workedSolution: { steps: [{ stepNumber: 1, description: "Resolve forces along the plane for A. The component of weight down the plane is 2g sin 30°.", workingLatex: "\\text{For A (up the plane): } T - 2g\\sin 30° = 2a", explanation: "A moves up the plane since B is heavier than the component pulling A down." }, { stepNumber: 2, description: "Write the equation for B (moving down).", workingLatex: "\\text{For B: } 3g - T = 3a", explanation: "" }, { stepNumber: 3, description: "Add the equations.", workingLatex: "3g - 2g\\sin 30° = 5a \\implies 3(9.8) - 2(9.8)(0.5) = 5a \\implies 29.4 - 9.8 = 5a \\implies a = \\frac{19.6}{5} = 3.92 \\text{ m/s}^2", explanation: "" }, { stepNumber: 4, description: "Find the tension from B's equation.", workingLatex: "T = 3g - 3a = 29.4 - 11.76 = 17.64 \\text{ N}", explanation: "" }], finalAnswer: "(a) \\(a = 3.92\\) m/s\\(^2\\). (b) \\(T = 17.64\\) N." } },
    { id: "y1f2-014", topicRef: "y1f2", topicTitle: "Connected Particles 14", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Standard", tags: ["two inclined planes", "pulley", "smooth", "acceleration"], questionText: "Two particles \\(P\\) and \\(Q\\), of masses \\(5\\) kg and \\(3\\) kg respectively, are connected by a light inextensible string passing over a smooth pulley at the top of a double inclined plane. The plane on which \\(P\\) rests makes an angle of \\(30°\\) with the horizontal and the plane on which \\(Q\\) rests makes an angle of \\(45°\\) with the horizontal. Both planes are smooth. Find the acceleration of the system and the tension in the string.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the component of weight along each plane.", workingLatex: "W_P = 5g\\sin 30° = 5(9.8)(0.5) = 24.5 \\text{ N}", explanation: "Component of P's weight down its plane." }, { stepNumber: 2, description: "Find Q's component.", workingLatex: "W_Q = 3g\\sin 45° = 3(9.8)\\left(\\frac{\\sqrt{2}}{2}\\right) \\approx 20.79 \\text{ N}", explanation: "Component of Q's weight down its plane." }, { stepNumber: 3, description: "Since W_P > W_Q, P moves down its plane and Q moves up its plane. Write equations of motion.", workingLatex: "\\text{For P (down its plane): } 5g\\sin 30° - T = 5a \\implies 24.5 - T = 5a \\quad \\cdots (1)", explanation: "" }, { stepNumber: 4, description: "Write the equation for Q.", workingLatex: "\\text{For Q (up its plane): } T - 3g\\sin 45° = 3a \\implies T - 20.79 = 3a \\quad \\cdots (2)", explanation: "" }, { stepNumber: 5, description: "Add (1) and (2).", workingLatex: "24.5 - 20.79 = 8a \\implies 3.71 = 8a \\implies a \\approx 0.464 \\text{ m/s}^2", explanation: "" }, { stepNumber: 6, description: "Find T from (2).", workingLatex: "T = 20.79 + 3(0.464) = 20.79 + 1.39 \\approx 22.2 \\text{ N}", explanation: "" }], finalAnswer: "\\(a \\approx 0.46\\) m/s\\(^2\\). \\(T \\approx 22.2\\) N." } },
    { id: "y1f2-015", topicRef: "y1f2", topicTitle: "Connected Particles 15", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Standard", tags: ["towing", "multi-stage", "acceleration", "constant speed"], questionText: "A car of mass \\(1200\\) kg tows a trailer of mass \\(800\\) kg along a straight horizontal road. The resistance to motion is \\(500\\) N on the car and \\(300\\) N on the trailer. The car accelerates from rest at \\(0.5\\) m/s\\(^2\\) until it reaches \\(15\\) m/s, then travels at constant speed. Find (a) the driving force during the acceleration phase and (b) the tension in the towbar during the constant speed phase.", workedSolution: { steps: [{ stepNumber: 1, description: "During the acceleration phase, apply F = ma to the whole system.", workingLatex: "D - 500 - 300 = (1200 + 800)(0.5) \\implies D - 800 = 1000 \\implies D = 1800 \\text{ N}", explanation: "D is the driving force of the engine." }, { stepNumber: 2, description: "During the constant speed phase, a = 0. Consider the whole system.", workingLatex: "D' - 500 - 300 = 0 \\implies D' = 800 \\text{ N}", explanation: "At constant speed, the driving force just balances total resistance." }, { stepNumber: 3, description: "Find the tension in the towbar during constant speed. Consider the trailer alone with a = 0.", workingLatex: "T - 300 = 0 \\implies T = 300 \\text{ N}", explanation: "At constant speed the tension balances the trailer's resistance." }], finalAnswer: "(a) Driving force \\(= 1800\\) N. (b) Tension in towbar \\(= 300\\) N." } },
    { id: "y1f2-016", topicRef: "y1f2", topicTitle: "Connected Particles 16", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["string breaks", "subsequent motion", "Atwood machine"], questionText: "Two particles of masses \\(2\\) kg and \\(8\\) kg are connected by a light inextensible string passing over a smooth fixed pulley. The system is released from rest. After \\(2\\) seconds the string breaks. Find (a) the speed of the particles when the string breaks and (b) the further distance the \\(2\\) kg particle travels upward after the string breaks.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the acceleration of the system while the string is intact.", workingLatex: "a = \\frac{(8 - 2)g}{8 + 2} = \\frac{6(9.8)}{10} = 5.88 \\text{ m/s}^2", explanation: "The 8 kg mass moves down, the 2 kg mass moves up." }, { stepNumber: 2, description: "Find the speed after 2 seconds.", workingLatex: "v = u + at = 0 + 5.88 \\times 2 = 11.76 \\text{ m/s}", explanation: "Both particles have this speed when the string breaks." }, { stepNumber: 3, description: "After the string breaks, the 2 kg particle moves upward at 11.76 m/s with only gravity acting on it (deceleration g = 9.8 m/s^2 downward).", workingLatex: "v^2 = u^2 + 2as \\implies 0 = 11.76^2 + 2(-9.8)s \\implies s = \\frac{138.30}{19.6} \\approx 7.06 \\text{ m}", explanation: "After the string breaks the 2 kg particle is in free flight." }], finalAnswer: "(a) Speed \\(= 11.76\\) m/s. (b) Further distance upward \\(\\approx 7.06\\) m." } },
    { id: "y1f2-017", topicRef: "y1f2", topicTitle: "Connected Particles 17", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["towbar", "tension", "thrust", "distinguishing"], questionText: "A car of mass \\(900\\) kg tows a trailer of mass \\(600\\) kg along a horizontal road. The resistance to motion is \\(300\\) N on the car and \\(200\\) N on the trailer. Find the force in the towbar and state whether it is a tension or a thrust when (a) the system accelerates at \\(0.4\\) m/s\\(^2\\) and (b) the system decelerates at \\(1.5\\) m/s\\(^2\\) with no engine force.", workedSolution: { steps: [{ stepNumber: 1, description: "Part (a): Consider the trailer alone with acceleration 0.4 m/s^2 forward.", workingLatex: "F - 200 = 600 \\times 0.4 = 240 \\implies F = 440 \\text{ N}", explanation: "F is positive so the towbar pulls the trailer forward: this is a tension." }, { stepNumber: 2, description: "Part (b): The system decelerates at 1.5 m/s^2. Consider the trailer alone. Acceleration = -1.5 m/s^2.", workingLatex: "F - 200 = 600 \\times (-1.5) = -900 \\implies F = -900 + 200 = -700 \\text{ N}", explanation: "F is negative, meaning the towbar pushes the trailer backward: this is a thrust (compression) of magnitude 700 N." }], finalAnswer: "(a) Tension of \\(440\\) N. (b) Thrust of \\(700\\) N." } },
    { id: "y1f2-018", topicRef: "y1f2", topicTitle: "Connected Particles 18", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["lift", "apparent weight", "scales"], questionText: "A person of mass \\(70\\) kg stands on scales in a lift. Find the reading on the scales (apparent weight) when the lift (a) accelerates upward at \\(1.2\\) m/s\\(^2\\) and (b) decelerates while going up at \\(0.8\\) m/s\\(^2\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Part (a): The lift accelerates upward, so the net upward force is ma.", workingLatex: "R - 70g = 70 \\times 1.2 \\implies R = 70(9.8) + 70(1.2) = 686 + 84 = 770 \\text{ N}", explanation: "The scales read the normal reaction R, which is greater than the true weight." }, { stepNumber: 2, description: "Part (b): The lift decelerates while going up, so the acceleration is directed downward at 0.8 m/s^2.", workingLatex: "R - 70g = 70 \\times (-0.8) \\implies R = 686 - 56 = 630 \\text{ N}", explanation: "The scales read less than the true weight when decelerating upward." }], finalAnswer: "(a) \\(R = 770\\) N. (b) \\(R = 630\\) N." } },
    { id: "y1f2-019", topicRef: "y1f2", topicTitle: "Connected Particles 19", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["table and pulley", "smooth", "speed", "distance"], questionText: "Particle \\(A\\) of mass \\(3\\) kg lies on a smooth horizontal table, \\(1.5\\) m from the edge. It is connected by a light inextensible string passing over a smooth pulley at the edge of the table to particle \\(B\\) of mass \\(2\\) kg hanging freely, \\(0.8\\) m above the floor. The system is released from rest. Find (a) the acceleration and (b) the speed at which \\(B\\) hits the floor.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the acceleration. B moves down, A moves along the table.", workingLatex: "2g - T = 2a \\quad \\text{and} \\quad T = 3a", explanation: "Equations of motion for B and A." }, { stepNumber: 2, description: "Add the equations.", workingLatex: "2g = 5a \\implies a = \\frac{2(9.8)}{5} = 3.92 \\text{ m/s}^2", explanation: "" }, { stepNumber: 3, description: "B falls 0.8 m. Find the speed using v^2 = u^2 + 2as.", workingLatex: "v^2 = 0 + 2(3.92)(0.8) = 6.272 \\implies v = \\sqrt{6.272} \\approx 2.50 \\text{ m/s}", explanation: "" }], finalAnswer: "(a) \\(a = 3.92\\) m/s\\(^2\\). (b) Speed \\(\\approx 2.50\\) m/s." } },
    { id: "y1f2-020", topicRef: "y1f2", topicTitle: "Connected Particles 20", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Standard", tags: ["Atwood machine", "distance", "time"], questionText: "Two particles of masses \\(4\\) kg and \\(6\\) kg are connected by a light inextensible string over a smooth pulley. They are released from rest with each particle \\(2\\) m from the pulley. Find (a) the acceleration, (b) the tension, and (c) the time taken for the heavier particle to descend \\(1\\) m.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the acceleration.", workingLatex: "a = \\frac{(6-4)g}{6+4} = \\frac{2(9.8)}{10} = 1.96 \\text{ m/s}^2", explanation: "" }, { stepNumber: 2, description: "Find the tension using the equation for the 4 kg mass.", workingLatex: "T - 4g = 4a \\implies T = 4(9.8) + 4(1.96) = 39.2 + 7.84 = 47.04 \\text{ N}", explanation: "" }, { stepNumber: 3, description: "Find the time for the 6 kg mass to descend 1 m.", workingLatex: "s = ut + \\tfrac{1}{2}at^2 \\implies 1 = 0 + \\tfrac{1}{2}(1.96)t^2 \\implies t^2 = \\frac{2}{1.96} \\approx 1.0204 \\implies t \\approx 1.01 \\text{ s}", explanation: "" }], finalAnswer: "(a) \\(a = 1.96\\) m/s\\(^2\\). (b) \\(T = 47.04\\) N. (c) \\(t \\approx 1.01\\) s." } },
    { id: "y1f2-021", topicRef: "y1f2", topicTitle: "Connected Particles 21", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["towing", "acceleration then braking", "two-stage"], questionText: "A car of mass \\(1000\\) kg tows a trailer of mass \\(500\\) kg along a horizontal road. The resistance to motion is \\(300\\) N on the car and \\(150\\) N on the trailer. The engine produces a driving force of \\(2250\\) N. (a) Find the acceleration. The car then removes the driving force and applies brakes, producing a braking force of \\(1500\\) N on the car only (resistances remain). (b) Find the deceleration and the force in the towbar during braking.", workedSolution: { steps: [{ stepNumber: 1, description: "Part (a): Whole system, acceleration phase.", workingLatex: "2250 - 300 - 150 = 1500a \\implies 1800 = 1500a \\implies a = 1.2 \\text{ m/s}^2", explanation: "" }, { stepNumber: 2, description: "Part (b): Whole system, braking phase. Engine force = 0, braking force = 1500 N backward, resistances = 450 N backward.", workingLatex: "-(1500 + 300 + 150) = 1500a \\implies a = \\frac{-1950}{1500} = -1.3 \\text{ m/s}^2", explanation: "Deceleration of 1.3 m/s^2." }, { stepNumber: 3, description: "Consider the trailer alone during braking. Let F be the towbar force (positive = tension).", workingLatex: "F - 150 = 500(-1.3) = -650 \\implies F = -650 + 150 = -500 \\text{ N}", explanation: "The negative sign indicates the towbar is in thrust (compression) of 500 N." }], finalAnswer: "(a) \\(a = 1.2\\) m/s\\(^2\\). (b) Deceleration \\(= 1.3\\) m/s\\(^2\\), towbar force is a thrust of \\(500\\) N." } },
    { id: "y1f2-022", topicRef: "y1f2", topicTitle: "Connected Particles 22", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Standard", tags: ["inclined plane", "pulley", "smooth", "two masses"], questionText: "A particle \\(A\\) of mass \\(4\\) kg lies on a smooth plane inclined at \\(40°\\) to the horizontal. A light inextensible string connects \\(A\\) over a smooth pulley at the top of the plane to a particle \\(B\\) of mass \\(5\\) kg hanging vertically. The system is released from rest. Find the acceleration and the tension in the string.", workedSolution: { steps: [{ stepNumber: 1, description: "The component of A's weight down the plane is 4g sin 40°.", workingLatex: "4g\\sin 40° = 4(9.8)(0.6428) \\approx 25.20 \\text{ N}", explanation: "" }, { stepNumber: 2, description: "B's weight is 5g = 49 N, which exceeds 25.20 N, so B descends.", workingLatex: "\\text{For B: } 5g - T = 5a \\quad \\cdots (1)", explanation: "" }, { stepNumber: 3, description: "Equation for A going up the plane.", workingLatex: "\\text{For A: } T - 4g\\sin 40° = 4a \\quad \\cdots (2)", explanation: "" }, { stepNumber: 4, description: "Add (1) and (2).", workingLatex: "5g - 4g\\sin 40° = 9a \\implies 49 - 25.20 = 9a \\implies a = \\frac{23.80}{9} \\approx 2.64 \\text{ m/s}^2", explanation: "" }, { stepNumber: 5, description: "Find T from (1).", workingLatex: "T = 5g - 5a = 49 - 5(2.64) = 49 - 13.22 \\approx 35.8 \\text{ N}", explanation: "" }], finalAnswer: "\\(a \\approx 2.64\\) m/s\\(^2\\). \\(T \\approx 35.8\\) N." } },
    { id: "y1f2-023", topicRef: "y1f2", topicTitle: "Connected Particles 23", yearCreated: 2026, examStyle: false, marks: 5, difficulty: "Standard", tags: ["Atwood machine", "hits ground", "subsequent motion"], questionText: "Two particles \\(P\\) (\\(3\\) kg) and \\(Q\\) (\\(5\\) kg) are connected by a light inextensible string over a smooth pulley. Initially \\(Q\\) is \\(1.2\\) m above the ground and \\(P\\) is on the ground. The system is released from rest. Find (a) the acceleration, (b) the speed at which \\(P\\) leaves the ground. (c) After \\(Q\\) hits the ground, describe the motion of \\(P\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Find the acceleration. Q is heavier so descends; P ascends.", workingLatex: "a = \\frac{(5-3)g}{5+3} = \\frac{2(9.8)}{8} = 2.45 \\text{ m/s}^2", explanation: "Q descends and P ascends." }, { stepNumber: 2, description: "Find the speed when Q hits the ground (Q falls 1.2 m).", workingLatex: "v^2 = 0 + 2(2.45)(1.2) = 5.88 \\implies v = \\sqrt{5.88} \\approx 2.42 \\text{ m/s}", explanation: "Both particles have this speed." }, { stepNumber: 3, description: "Part (c): When Q hits the ground, the string goes slack. P is now 1.2 m above the ground, moving upward at 2.42 m/s. P becomes a projectile under gravity.", workingLatex: "\\text{P continues upward, decelerating at } g = 9.8 \\text{ m/s}^2 \\text{, rises a further } s = \\frac{v^2}{2g} = \\frac{5.88}{19.6} = 0.3 \\text{ m}", explanation: "P reaches a maximum height of 1.2 + 0.3 = 1.5 m, then falls back to the ground." }], finalAnswer: "(a) \\(a = 2.45\\) m/s\\(^2\\). (b) Speed \\(\\approx 2.42\\) m/s. (c) After \\(Q\\) hits the ground, \\(P\\) continues upward a further \\(0.3\\) m (to height \\(1.5\\) m) then falls freely back to the ground." } },
    { id: "y1f2-024", topicRef: "y1f2", topicTitle: "Connected Particles 24", yearCreated: 2026, examStyle: false, marks: 4, difficulty: "Standard", tags: ["table and pulley", "distance to edge", "reaches edge"], questionText: "A particle \\(A\\) of mass \\(5\\) kg lies on a smooth horizontal table, \\(2\\) m from the pulley at the edge. A light inextensible string passes over the pulley and connects to a particle \\(B\\) of mass \\(3\\) kg hanging freely. The system is released from rest. Find how long it takes for \\(A\\) to reach the edge of the table.", workedSolution: { steps: [{ stepNumber: 1, description: "Find the acceleration.", workingLatex: "3g = (5 + 3)a \\implies a = \\frac{3(9.8)}{8} = 3.675 \\text{ m/s}^2", explanation: "B's weight drives the system; A's mass and B's mass resist." }, { stepNumber: 2, description: "Find the time for A to travel 2 m from rest.", workingLatex: "s = \\tfrac{1}{2}at^2 \\implies 2 = \\tfrac{1}{2}(3.675)t^2 \\implies t^2 = \\frac{4}{3.675} \\approx 1.0884 \\implies t \\approx 1.04 \\text{ s}", explanation: "" }], finalAnswer: "\\(t \\approx 1.04\\) s." } },
    { id: "y1f2-025", topicRef: "y1f2", topicTitle: "Connected Particles 25", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Challenge", tags: ["Atwood machine", "show that", "algebraic", "acceleration"], questionText: "Two particles of masses \\(M\\) and \\(m\\) (where \\(M > m\\)) are connected by a light inextensible string passing over a smooth fixed pulley. The system is released from rest. Show that the acceleration of the system is \\(\\dfrac{(M - m)g}{M + m}\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Let the acceleration be a (M moves down, m moves up). Write the equation of motion for M.", workingLatex: "Mg - T = Ma \\quad \\cdots (1)", explanation: "" }, { stepNumber: 2, description: "Write the equation of motion for m.", workingLatex: "T - mg = ma \\quad \\cdots (2)", explanation: "" }, { stepNumber: 3, description: "Add equations (1) and (2) to eliminate T.", workingLatex: "Mg - mg = Ma + ma \\implies (M - m)g = (M + m)a", explanation: "" }, { stepNumber: 4, description: "Solve for a.", workingLatex: "a = \\frac{(M - m)g}{M + m}", explanation: "As required." }], finalAnswer: "\\(a = \\dfrac{(M - m)g}{M + m}\\) as required." } },
    { id: "y1f2-026", topicRef: "y1f2", topicTitle: "Connected Particles 26", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Challenge", tags: ["Atwood machine", "show that", "algebraic", "tension"], questionText: "Two particles of masses \\(M\\) and \\(m\\) (where \\(M > m\\)) are connected by a light inextensible string passing over a smooth fixed pulley. Show that the tension in the string is \\(\\dfrac{2Mmg}{M + m}\\).", workedSolution: { steps: [{ stepNumber: 1, description: "From the standard Atwood result, the acceleration is a = (M - m)g / (M + m).", workingLatex: "a = \\frac{(M - m)g}{M + m}", explanation: "Derived by adding the two equations of motion." }, { stepNumber: 2, description: "Use the equation of motion for mass m: T - mg = ma.", workingLatex: "T = mg + ma = m\\left(g + \\frac{(M - m)g}{M + m}\\right)", explanation: "" }, { stepNumber: 3, description: "Simplify the expression inside the bracket.", workingLatex: "T = m \\cdot \\frac{g(M + m) + (M - m)g}{M + m} = m \\cdot \\frac{gM + gm + gM - gm}{M + m} = m \\cdot \\frac{2Mg}{M + m}", explanation: "" }, { stepNumber: 4, description: "State the final result.", workingLatex: "T = \\frac{2Mmg}{M + m}", explanation: "As required." }], finalAnswer: "\\(T = \\dfrac{2Mmg}{M + m}\\) as required." } },
    { id: "y1f2-027", topicRef: "y1f2", topicTitle: "Connected Particles 27", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Challenge", tags: ["Atwood machine", "algebraic", "show that", "specific masses"], questionText: "Two particles of masses \\(m\\) and \\(3m\\) are connected by a light inextensible string passing over a smooth fixed pulley. The system is released from rest. Show that the acceleration is \\(\\dfrac{g}{2}\\) and find the tension in terms of \\(m\\) and \\(g\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Apply the Atwood formula with M = 3m and m = m.", workingLatex: "a = \\frac{(3m - m)g}{3m + m} = \\frac{2mg}{4m} = \\frac{g}{2}", explanation: "As required." }, { stepNumber: 2, description: "Find the tension using the equation for the lighter mass.", workingLatex: "T - mg = m \\cdot \\frac{g}{2} \\implies T = mg + \\frac{mg}{2} = \\frac{3mg}{2}", explanation: "Alternatively, using the formula T = 2Mmg/(M+m) = 2(3m)(m)g/(4m) = 3mg/2." }], finalAnswer: "Acceleration \\(= \\dfrac{g}{2}\\) as required. Tension \\(= \\dfrac{3mg}{2}\\)." } },
    { id: "y1f2-028", topicRef: "y1f2", topicTitle: "Connected Particles 28", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Challenge", tags: ["table and pulley", "rough surface", "friction", "acceleration"], questionText: "A particle \\(A\\) of mass \\(2\\) kg lies on a rough horizontal table. The friction force between \\(A\\) and the table is \\(5\\) N. A light inextensible string connects \\(A\\) over a smooth pulley at the edge of the table to a particle \\(B\\) of mass \\(3\\) kg hanging freely. The system is released from rest. Find the acceleration and the tension in the string.", workedSolution: { steps: [{ stepNumber: 1, description: "For B (moving down):", workingLatex: "3g - T = 3a \\quad \\cdots (1)", explanation: "" }, { stepNumber: 2, description: "For A (moving along table against friction):", workingLatex: "T - 5 = 2a \\quad \\cdots (2)", explanation: "Friction 5 N opposes the motion." }, { stepNumber: 3, description: "Add (1) and (2).", workingLatex: "3g - 5 = 5a \\implies 29.4 - 5 = 5a \\implies 24.4 = 5a \\implies a = 4.88 \\text{ m/s}^2", explanation: "" }, { stepNumber: 4, description: "Find T from (2).", workingLatex: "T = 2(4.88) + 5 = 9.76 + 5 = 14.76 \\text{ N}", explanation: "" }], finalAnswer: "\\(a = 4.88\\) m/s\\(^2\\). \\(T = 14.76\\) N." } },
    { id: "y1f2-029", topicRef: "y1f2", topicTitle: "Connected Particles 29", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["table and pulley", "rough surface", "show that", "algebraic"], questionText: "A particle \\(A\\) of mass \\(2m\\) on a rough horizontal table is connected by a light inextensible string over a smooth pulley to a particle \\(B\\) of mass \\(3m\\) hanging freely. The friction force on \\(A\\) is \\(F\\). Show that the acceleration of the system is \\(\\dfrac{3mg - F}{5m}\\).", workedSolution: { steps: [{ stepNumber: 1, description: "For B (moving down):", workingLatex: "3mg - T = 3ma \\quad \\cdots (1)", explanation: "" }, { stepNumber: 2, description: "For A (moving along table against friction F):", workingLatex: "T - F = 2ma \\quad \\cdots (2)", explanation: "" }, { stepNumber: 3, description: "Add (1) and (2) to eliminate T.", workingLatex: "3mg - F = 3ma + 2ma = 5ma", explanation: "" }, { stepNumber: 4, description: "Solve for a.", workingLatex: "a = \\frac{3mg - F}{5m}", explanation: "As required. Note this is only valid when 3mg > F, otherwise the system does not move." }], finalAnswer: "\\(a = \\dfrac{3mg - F}{5m}\\) as required." } },
    { id: "y1f2-030", topicRef: "y1f2", topicTitle: "Connected Particles 30", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["three bodies", "connected", "acceleration", "two tensions"], questionText: "Three particles \\(A\\), \\(B\\), and \\(C\\) of masses \\(2\\) kg, \\(3\\) kg, and \\(5\\) kg respectively are connected in a line by two light inextensible strings on a smooth horizontal surface. A horizontal force of \\(40\\) N is applied to \\(C\\) in the direction of the line \\(A\\text{-}B\\text{-}C\\). Find (a) the acceleration, (b) the tension \\(T_1\\) in the string between \\(A\\) and \\(B\\), and (c) the tension \\(T_2\\) in the string between \\(B\\) and \\(C\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Consider the whole system.", workingLatex: "40 = (2 + 3 + 5)a = 10a \\implies a = 4 \\text{ m/s}^2", explanation: "" }, { stepNumber: 2, description: "Consider particle A alone. The only force on A is T_1.", workingLatex: "T_1 = 2 \\times 4 = 8 \\text{ N}", explanation: "" }, { stepNumber: 3, description: "Consider particles A and B together. The external force on this sub-system is T_2 (from the string to C).", workingLatex: "T_2 = (2 + 3) \\times 4 = 20 \\text{ N}", explanation: "Alternatively, consider C alone: 40 - T_2 = 5(4) gives T_2 = 20 N." }], finalAnswer: "(a) \\(a = 4\\) m/s\\(^2\\). (b) \\(T_1 = 8\\) N. (c) \\(T_2 = 20\\) N." } },
    { id: "y1f2-031", topicRef: "y1f2", topicTitle: "Connected Particles 31", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["inclined plane", "pulley", "rough", "friction", "acceleration"], questionText: "A particle \\(A\\) of mass \\(4\\) kg is placed on a rough plane inclined at \\(30°\\) to the horizontal. The friction force on \\(A\\) is \\(6\\) N. A light inextensible string connects \\(A\\) over a smooth pulley at the top of the plane to a particle \\(B\\) of mass \\(5\\) kg hanging freely. The system is released from rest. Find the acceleration and the tension in the string.", workedSolution: { steps: [{ stepNumber: 1, description: "Check the direction of motion. B's weight is 5g = 49 N downward. A's weight component down the plane is 4g sin 30 = 19.6 N. Since 49 > 19.6 + 6 (friction), B descends and A moves up the plane.", workingLatex: "\\text{For B: } 5g - T = 5a \\quad \\cdots (1)", explanation: "" }, { stepNumber: 2, description: "For A moving up the plane (friction acts down the plane opposing motion):", workingLatex: "\\text{For A: } T - 4g\\sin 30° - 6 = 4a \\implies T - 19.6 - 6 = 4a \\implies T - 25.6 = 4a \\quad \\cdots (2)", explanation: "" }, { stepNumber: 3, description: "Add (1) and (2).", workingLatex: "5g - 25.6 = 9a \\implies 49 - 25.6 = 9a \\implies 23.4 = 9a \\implies a = 2.6 \\text{ m/s}^2", explanation: "" }, { stepNumber: 4, description: "Find T from (1).", workingLatex: "T = 5g - 5a = 49 - 13 = 36 \\text{ N}", explanation: "" }], finalAnswer: "\\(a = 2.6\\) m/s\\(^2\\). \\(T = 36\\) N." } },
    { id: "y1f2-032", topicRef: "y1f2", topicTitle: "Connected Particles 32", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["inclined plane", "pulley", "algebraic", "show that", "determine direction"], questionText: "A particle \\(P\\) of mass \\(2\\) kg lies on a smooth plane inclined at angle \\(\\theta\\) to the horizontal, where \\(\\sin\\theta = \\frac{3}{5}\\). A light inextensible string connects \\(P\\) over a smooth pulley at the top of the plane to a particle \\(Q\\) of mass \\(1\\) kg hanging freely. (a) Determine which direction the system moves. (b) Find the acceleration. (c) Show that the tension is \\(\\dfrac{16g}{15}\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Part (a): Compare the driving forces. P's weight component down the plane is 2g sin theta, Q's weight is g.", workingLatex: "2g\\sin\\theta = 2g \\times \\frac{3}{5} = \\frac{6g}{5} = 1.2g", explanation: "Since 1.2g > g, P's weight component exceeds Q's weight. So P moves down the plane and Q moves up." }, { stepNumber: 2, description: "Part (b): Write the equations of motion. P moves down the plane.", workingLatex: "\\text{For P: } 2g\\sin\\theta - T = 2a \\implies \\frac{6g}{5} - T = 2a \\quad \\cdots (1)", explanation: "" }, { stepNumber: 3, description: "Q moves up.", workingLatex: "\\text{For Q: } T - g = a \\quad \\cdots (2)", explanation: "" }, { stepNumber: 4, description: "Add (1) and (2).", workingLatex: "\\frac{6g}{5} - g = 3a \\implies \\frac{6g - 5g}{5} = 3a \\implies \\frac{g}{5} = 3a \\implies a = \\frac{g}{15}", explanation: "" }, { stepNumber: 5, description: "Part (c): Substitute into (2) to find T.", workingLatex: "T = g + a = g + \\frac{g}{15} = \\frac{15g + g}{15} = \\frac{16g}{15}", explanation: "As required." }], finalAnswer: "(a) \\(P\\) moves down the plane. (b) \\(a = \\dfrac{g}{15}\\). (c) \\(T = \\dfrac{16g}{15}\\) as required." } },
    { id: "y1f2-033", topicRef: "y1f2", topicTitle: "Connected Particles 33", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["three bodies", "vertical", "acceleration", "tension"], questionText: "Three particles \\(A\\), \\(B\\), and \\(C\\) of masses \\(1\\) kg, \\(2\\) kg, and \\(3\\) kg respectively hang in a vertical line connected by two light inextensible strings, with \\(A\\) at the top attached to a fixed support, \\(B\\) in the middle, and \\(C\\) at the bottom. The support is then removed and the system falls freely. Find the tension in each string immediately after the support is removed.", workedSolution: { steps: [{ stepNumber: 1, description: "Once the support is removed, the entire system is in free fall. Every particle accelerates at g downward.", workingLatex: "a = g \\text{ for all particles}", explanation: "There are no external forces other than gravity to create any relative acceleration between the particles." }, { stepNumber: 2, description: "Consider particle C (the lowest). The forces on C are weight 3g downward and tension T_2 in the string BC upward.", workingLatex: "3g - T_2 = 3g \\implies T_2 = 0", explanation: "For C to accelerate at g, the net force must be 3g. Since weight alone is 3g, the tension must be zero." }, { stepNumber: 3, description: "Consider particle B. The forces are weight 2g downward, T_2 pulling downward from C (= 0), and T_1 pulling upward from A.", workingLatex: "2g + T_2 - T_1 = 2g \\implies 2g + 0 - T_1 = 2g \\implies T_1 = 0", explanation: "Similarly, for B to accelerate at g, T_1 must be zero." }], finalAnswer: "Both tensions are \\(0\\) N. In free fall, the strings are slack and carry no tension." } },
    { id: "y1f2-034", topicRef: "y1f2", topicTitle: "Connected Particles 34", yearCreated: 2026, examStyle: true, marks: 8, difficulty: "Challenge", tags: ["table and pulley", "hits floor", "subsequent motion", "multi-part"], questionText: "A particle \\(A\\) of mass \\(3\\) kg rests on a smooth horizontal table, \\(4\\) m from the edge. A light inextensible string passes over a smooth pulley at the edge and connects to a particle \\(B\\) of mass \\(2\\) kg, hanging \\(1.5\\) m above the ground. The system is released from rest. (a) Find the acceleration. (b) Find the speed when \\(B\\) hits the ground. (c) Describe the subsequent motion of \\(A\\). (d) Find the total distance \\(A\\) travels before stopping at the edge of the table.", workedSolution: { steps: [{ stepNumber: 1, description: "Part (a): Find the acceleration.", workingLatex: "2g = (3 + 2)a \\implies a = \\frac{2(9.8)}{5} = 3.92 \\text{ m/s}^2", explanation: "Only B's weight drives the system." }, { stepNumber: 2, description: "Part (b): B falls 1.5 m from rest.", workingLatex: "v^2 = 0 + 2(3.92)(1.5) = 11.76 \\implies v = \\sqrt{11.76} \\approx 3.43 \\text{ m/s}", explanation: "" }, { stepNumber: 3, description: "Part (c): When B hits the ground, the string goes slack. A is now 4 - 1.5 = 2.5 m from the edge, moving at 3.43 m/s toward the edge. On the smooth table with no string tension, there is no horizontal force, so A continues at constant speed 3.43 m/s.", workingLatex: "\\text{A continues at } 3.43 \\text{ m/s (constant) across the smooth table.}", explanation: "No friction and no tension means no horizontal force on A." }, { stepNumber: 4, description: "Part (d): A has already moved 1.5 m (while B fell). A then travels a further 2.5 m to the edge at constant speed. Total distance = 1.5 + 2.5 = 4 m.", workingLatex: "\\text{Total distance} = 1.5 + 2.5 = 4 \\text{ m}", explanation: "A started 4 m from the edge and reaches the edge, so it travels exactly 4 m in total." }], finalAnswer: "(a) \\(a = 3.92\\) m/s\\(^2\\). (b) Speed \\(\\approx 3.43\\) m/s. (c) \\(A\\) continues at constant speed \\(3.43\\) m/s across the smooth table. (d) Total distance \\(= 4\\) m." } },
    { id: "y1f2-035", topicRef: "y1f2", topicTitle: "Connected Particles 35", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["towing", "resistance proportional to mass", "acceleration", "tension"], questionText: "A car of mass \\(M\\) tows a trailer of mass \\(m\\) along a horizontal road with a driving force \\(D\\). The resistance to motion on each vehicle is proportional to its mass, with total resistance \\(R\\). Show that the tension in the towbar is \\(\\dfrac{mD}{M + m}\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Since resistance is proportional to mass, the resistance on the trailer is mR/(M+m) and the resistance on the car is MR/(M+m).", workingLatex: "R_{\\text{trailer}} = \\frac{mR}{M + m}, \\quad R_{\\text{car}} = \\frac{MR}{M + m}", explanation: "Resistances are in the ratio of the masses, and their sum is R." }, { stepNumber: 2, description: "Find the acceleration of the whole system.", workingLatex: "D - R = (M + m)a \\implies a = \\frac{D - R}{M + m}", explanation: "" }, { stepNumber: 3, description: "Apply F = ma to the trailer alone. The forward force is T and the backward force is the trailer's share of resistance.", workingLatex: "T - \\frac{mR}{M + m} = m \\cdot \\frac{D - R}{M + m} = \\frac{m(D - R)}{M + m}", explanation: "" }, { stepNumber: 4, description: "Solve for T.", workingLatex: "T = \\frac{m(D - R)}{M + m} + \\frac{mR}{M + m} = \\frac{mD - mR + mR}{M + m} = \\frac{mD}{M + m}", explanation: "As required. Note that when resistance is proportional to mass, the resistance cancels in the towbar tension formula." }], finalAnswer: "\\(T = \\dfrac{mD}{M + m}\\) as required." } },
    { id: "y1f2-036", topicRef: "y1f2", topicTitle: "Connected Particles 36", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["two inclined planes", "rough", "show that", "equilibrium"], questionText: "A particle \\(P\\) of mass \\(4\\) kg lies on a rough plane inclined at \\(30°\\) to the horizontal. A light inextensible string connects \\(P\\) over a smooth pulley at the top to a particle \\(Q\\) of mass \\(3\\) kg on a smooth plane inclined at \\(45°\\) on the other side. The friction force on \\(P\\) is \\(4\\) N. (a) Determine which direction the system moves. (b) Find the acceleration. (c) Find the tension.", workedSolution: { steps: [{ stepNumber: 1, description: "Part (a): Compare the weight components along each plane.", workingLatex: "W_P = 4g\\sin 30° = 4(9.8)(0.5) = 19.6 \\text{ N (down P's plane)}", explanation: "" }, { stepNumber: 2, description: "Find Q's weight component.", workingLatex: "W_Q = 3g\\sin 45° = 3(9.8)(0.7071) \\approx 20.79 \\text{ N (down Q's plane)}", explanation: "" }, { stepNumber: 3, description: "Since W_Q > W_P, Q tends to move down its plane and P moves up its plane. Friction on P opposes P's motion (acts down P's plane).", workingLatex: "\\text{Net driving force} = W_Q - W_P - F = 20.79 - 19.6 - 4 = -2.81 \\text{ N}", explanation: "This is negative, meaning the system does NOT move in the assumed direction. Check if it moves the other way: if P moves down its plane, friction acts up P's plane." }, { stepNumber: 4, description: "Try the other direction: P moves down its plane, Q moves up.", workingLatex: "\\text{Net force} = W_P - W_Q - F = 19.6 - 20.79 - 4 = -5.19 \\text{ N}", explanation: "This is also negative. So the system cannot move in either direction. The system is in equilibrium." }, { stepNumber: 5, description: "The system is in equilibrium. The friction force adjusts to maintain equilibrium. Find the actual friction and tension.", workingLatex: "T = W_Q = 3g\\sin 45° \\approx 20.79 \\text{ N}", explanation: "Since Q's plane is smooth, Q is in equilibrium only if T = W_Q." }, { stepNumber: 6, description: "For P: T + F_r = W_P gives the actual friction, where F_r could be up or down the plane.", workingLatex: "\\text{Along P's plane: } T - W_P = 20.79 - 19.6 = 1.19 \\text{ N}", explanation: "The tension exceeds P's weight component, so friction acts down the plane with magnitude 1.19 N (which is less than the maximum 4 N)." }], finalAnswer: "The system is in equilibrium. \\(T \\approx 20.8\\) N. The actual friction on \\(P\\) is approximately \\(1.19\\) N acting down the plane." } },
    { id: "y1f2-037", topicRef: "y1f2", topicTitle: "Connected Particles 37", yearCreated: 2026, examStyle: true, marks: 8, difficulty: "Challenge", tags: ["Atwood machine", "multi-part", "hits ground", "slack string", "maximum height"], questionText: "Particles \\(P\\) (\\(2\\) kg) and \\(Q\\) (\\(5\\) kg) are connected by a light inextensible string over a smooth fixed pulley. Initially both particles are \\(3\\) m above the ground. The system is released from rest. (a) Find the acceleration. (b) Find the speed at which \\(Q\\) hits the ground. (c) Find the greatest height reached by \\(P\\) above the ground. (d) Find the total time from release until \\(P\\) hits the ground.", workedSolution: { steps: [{ stepNumber: 1, description: "Part (a): Q descends, P ascends.", workingLatex: "a = \\frac{(5 - 2)g}{5 + 2} = \\frac{3(9.8)}{7} = 4.2 \\text{ m/s}^2", explanation: "" }, { stepNumber: 2, description: "Part (b): Q falls 3 m to the ground.", workingLatex: "v^2 = 0 + 2(4.2)(3) = 25.2 \\implies v = \\sqrt{25.2} \\approx 5.02 \\text{ m/s}", explanation: "Both particles have this speed." }, { stepNumber: 3, description: "When Q hits the ground, P is at height 3 + 3 = 6 m, moving upward at 5.02 m/s. The string goes slack.", workingLatex: "\\text{P at } 6 \\text{ m, moving up at } 5.02 \\text{ m/s}", explanation: "" }, { stepNumber: 4, description: "Part (c): P continues upward under gravity alone.", workingLatex: "0 = 5.02^2 - 2(9.8)s \\implies s = \\frac{25.2}{19.6} \\approx 1.286 \\text{ m}", explanation: "P rises a further 1.286 m." }, { stepNumber: 5, description: "Greatest height of P.", workingLatex: "h_{\\max} = 6 + 1.286 \\approx 7.29 \\text{ m}", explanation: "" }, { stepNumber: 6, description: "Part (d): Find the time for Q to fall 3 m (phase 1).", workingLatex: "3 = \\tfrac{1}{2}(4.2)t_1^2 \\implies t_1^2 = \\frac{6}{4.2} \\approx 1.4286 \\implies t_1 \\approx 1.195 \\text{ s}", explanation: "" }, { stepNumber: 7, description: "After the string goes slack, P is at 6 m moving up at 5.02 m/s. P rises then falls to the ground (height 0). Use s = ut + (1/2)at^2 with s = -6 (net displacement downward), u = 5.02, a = -9.8.", workingLatex: "-6 = 5.02t_2 - 4.9t_2^2 \\implies 4.9t_2^2 - 5.02t_2 - 6 = 0", explanation: "" }, { stepNumber: 8, description: "Solve the quadratic.", workingLatex: "t_2 = \\frac{5.02 + \\sqrt{5.02^2 + 4(4.9)(6)}}{2(4.9)} = \\frac{5.02 + \\sqrt{25.20 + 117.6}}{9.8} = \\frac{5.02 + \\sqrt{142.8}}{9.8} = \\frac{5.02 + 11.95}{9.8} \\approx \\frac{16.97}{9.8} \\approx 1.732 \\text{ s}", explanation: "Taking the positive root." }, { stepNumber: 9, description: "Total time.", workingLatex: "t = t_1 + t_2 \\approx 1.195 + 1.732 \\approx 2.93 \\text{ s}", explanation: "" }], finalAnswer: "(a) \\(a = 4.2\\) m/s\\(^2\\). (b) Speed \\(\\approx 5.02\\) m/s. (c) Greatest height \\(\\approx 7.29\\) m. (d) Total time \\(\\approx 2.93\\) s." } },
    { id: "y1f2-038", topicRef: "y1f2", topicTitle: "Connected Particles 38", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["table and pulley", "rough", "algebraic", "show that", "tension"], questionText: "A particle \\(A\\) of mass \\(m\\) lies on a rough horizontal table. A light inextensible string connects \\(A\\) over a smooth pulley at the edge of the table to a particle \\(B\\) of mass \\(2m\\) hanging freely. The friction force on \\(A\\) is \\(F\\). The system is released from rest. (a) Show that the acceleration is \\(\\dfrac{2mg - F}{3m}\\). (b) Show that the tension is \\(\\dfrac{m(2mg + 2F)}{3m} = \\dfrac{2m g + 2F}{3}\\). (c) State the condition for the system to move.", workedSolution: { steps: [{ stepNumber: 1, description: "Part (a): For B (descending):", workingLatex: "2mg - T = 2ma \\quad \\cdots (1)", explanation: "" }, { stepNumber: 2, description: "For A (moving along table against friction):", workingLatex: "T - F = ma \\quad \\cdots (2)", explanation: "" }, { stepNumber: 3, description: "Add (1) and (2).", workingLatex: "2mg - F = 3ma \\implies a = \\frac{2mg - F}{3m}", explanation: "As required." }, { stepNumber: 4, description: "Part (b): Substitute a into (2).", workingLatex: "T = ma + F = m \\cdot \\frac{2mg - F}{3m} + F = \\frac{2mg - F}{3} + F = \\frac{2mg - F + 3F}{3} = \\frac{2mg + 2F}{3}", explanation: "As required." }, { stepNumber: 5, description: "Part (c): For the system to move, the acceleration must be positive.", workingLatex: "\\frac{2mg - F}{3m} > 0 \\implies 2mg > F \\implies F < 2mg", explanation: "The weight of B must exceed the friction on A." }], finalAnswer: "(a) \\(a = \\dfrac{2mg - F}{3m}\\) as required. (b) \\(T = \\dfrac{2mg + 2F}{3}\\) as required. (c) The system moves when \\(F < 2mg\\)." } },
    { id: "y1f2-039", topicRef: "y1f2", topicTitle: "Connected Particles 39", yearCreated: 2026, examStyle: true, marks: 8, difficulty: "Challenge", tags: ["inclined plane", "pulley", "algebraic", "show that", "two masses"], questionText: "A particle \\(A\\) of mass \\(m\\) lies on a smooth plane inclined at angle \\(\\alpha\\) to the horizontal. A light inextensible string passes over a smooth pulley at the top of the plane and connects \\(A\\) to a particle \\(B\\) of mass \\(M\\) hanging freely (where \\(M > m\\sin\\alpha\\)). (a) Show that the acceleration is \\(\\dfrac{(M - m\\sin\\alpha)g}{M + m}\\). (b) Show that the tension is \\(\\dfrac{Mmg(1 + \\sin\\alpha)}{M + m}\\). (c) Verify that when \\(\\alpha = 90°\\), the results reduce to the standard Atwood machine formulas.", workedSolution: { steps: [{ stepNumber: 1, description: "Part (a): B descends, A moves up the plane. For B:", workingLatex: "Mg - T = Ma \\quad \\cdots (1)", explanation: "" }, { stepNumber: 2, description: "For A (up the smooth incline):", workingLatex: "T - mg\\sin\\alpha = ma \\quad \\cdots (2)", explanation: "" }, { stepNumber: 3, description: "Add (1) and (2).", workingLatex: "Mg - mg\\sin\\alpha = (M + m)a \\implies a = \\frac{(M - m\\sin\\alpha)g}{M + m}", explanation: "As required." }, { stepNumber: 4, description: "Part (b): Substitute a into (2) to find T.", workingLatex: "T = ma + mg\\sin\\alpha = m\\left(\\frac{(M - m\\sin\\alpha)g}{M + m}\\right) + mg\\sin\\alpha", explanation: "" }, { stepNumber: 5, description: "Simplify.", workingLatex: "T = \\frac{m(M - m\\sin\\alpha)g}{M + m} + \\frac{mg\\sin\\alpha(M + m)}{M + m} = \\frac{mMg - m^2 g\\sin\\alpha + mMg\\sin\\alpha + m^2 g\\sin\\alpha}{M + m}", explanation: "" }, { stepNumber: 6, description: "The m^2 g sin alpha terms cancel.", workingLatex: "T = \\frac{mMg + mMg\\sin\\alpha}{M + m} = \\frac{Mmg(1 + \\sin\\alpha)}{M + m}", explanation: "As required." }, { stepNumber: 7, description: "Part (c): When alpha = 90 degrees, sin alpha = 1.", workingLatex: "a = \\frac{(M - m)g}{M + m}, \\quad T = \\frac{2Mmg}{M + m}", explanation: "These are the standard Atwood machine results, as expected." }], finalAnswer: "(a) \\(a = \\dfrac{(M - m\\sin\\alpha)g}{M + m}\\) as required. (b) \\(T = \\dfrac{Mmg(1 + \\sin\\alpha)}{M + m}\\) as required. (c) When \\(\\alpha = 90°\\), these reduce to \\(a = \\dfrac{(M-m)g}{M+m}\\) and \\(T = \\dfrac{2Mmg}{M+m}\\)." } },
    { id: "y1f2-040", topicRef: "y1f2", topicTitle: "Connected Particles 40", yearCreated: 2026, examStyle: true, marks: 9, difficulty: "Challenge", tags: ["table and pulley", "rough", "multi-part", "hits floor", "slack string", "stopping distance"], questionText: "Particle \\(A\\) of mass \\(4\\) kg lies on a rough horizontal table, \\(5\\) m from the edge. The friction force on \\(A\\) is \\(8\\) N. A light inextensible string passes over a smooth pulley at the edge and connects to particle \\(B\\) of mass \\(6\\) kg, hanging \\(2\\) m above the floor. The system is released from rest. (a) Show that the acceleration is \\(5.08\\) m/s\\(^2\\). (b) Find the speed when \\(B\\) hits the floor. (c) After \\(B\\) hits the floor, the string goes slack. Find how much further \\(A\\) travels before coming to rest. (d) Does \\(A\\) reach the edge of the table?", workedSolution: { steps: [{ stepNumber: 1, description: "Part (a): For B (descending):", workingLatex: "6g - T = 6a \\quad \\cdots (1)", explanation: "" }, { stepNumber: 2, description: "For A (moving along table against friction 8 N):", workingLatex: "T - 8 = 4a \\quad \\cdots (2)", explanation: "" }, { stepNumber: 3, description: "Add (1) and (2).", workingLatex: "6g - 8 = 10a \\implies 6(9.8) - 8 = 10a \\implies 50.8 = 10a \\implies a = 5.08 \\text{ m/s}^2", explanation: "As required." }, { stepNumber: 4, description: "Part (b): B falls 2 m from rest with acceleration 5.08 m/s^2.", workingLatex: "v^2 = 0 + 2(5.08)(2) = 20.32 \\implies v = \\sqrt{20.32} \\approx 4.51 \\text{ m/s}", explanation: "" }, { stepNumber: 5, description: "Part (c): After B hits the floor, the string goes slack. A is moving at 4.51 m/s with friction 8 N opposing its motion. Deceleration = F/m = 8/4 = 2 m/s^2.", workingLatex: "v^2 = u^2 + 2as \\implies 0 = 4.51^2 - 2(2)s \\implies s = \\frac{20.32}{4} = 5.08 \\text{ m}", explanation: "A would travel a further 5.08 m before friction brings it to rest." }, { stepNumber: 6, description: "Part (d): While B fell, A moved 2 m along the table. A is now 5 - 2 = 3 m from the edge. A needs 5.08 m to stop, but only 3 m of table remains.", workingLatex: "\\text{Since } 5.08 > 3, \\text{ A reaches the edge of the table before stopping.}", explanation: "A reaches the edge and falls off." }], finalAnswer: "(a) \\(a = 5.08\\) m/s\\(^2\\) as required. (b) Speed \\(\\approx 4.51\\) m/s. (c) \\(A\\) would travel a further \\(5.08\\) m. (d) Yes, since \\(A\\) is only \\(3\\) m from the edge, it reaches the edge before stopping." } },
];
